'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Menu, X, Plus, MessageSquare, Search, Settings, LogOut,
  ChevronRight, Calendar, Clock, Hash, ChevronLeft, Scale
} from 'lucide-react';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Card } from '@/components/ui/Card';
import { ChatSession } from '@/lib/types';
import { chatService } from '@/services/chat.service';
import { cn } from '@/lib/utils/cn';

interface SidebarProps {
  currentSessionId?: string;
  onSessionSelect: (sessionId: string) => void;
  onNewChat: () => void;
}

export function Sidebar({ currentSessionId, onSessionSelect, onNewChat }: SidebarProps) {
  const [isOpen, setIsOpen] = useState(true);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    loadSessions();
  }, []);

  const loadSessions = async () => {
    try {
      setIsLoading(true);
      const data = await chatService.getSessions();
      setSessions(data);
    } catch (error) {
      console.error('Failed to load sessions:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDeleteSession = async (sessionId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    
    try {
      await chatService.deleteSession(sessionId);
      setSessions((prev) => prev.filter((s) => s.id !== sessionId));
      
      if (currentSessionId === sessionId) {
        onNewChat();
      }
    } catch (error) {
      console.error('Failed to delete session:', error);
    }
  };

  const filteredSessions = sessions.filter((session) =>
    session.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const formatDate = (date: Date) => {
    const now = new Date();
    const sessionDate = new Date(date);
    const diffInDays = Math.floor((now.getTime() - sessionDate.getTime()) / (1000 * 60 * 60 * 24));

    if (diffInDays === 0) return 'Today';
    if (diffInDays === 1) return 'Yesterday';
    if (diffInDays < 7) return `${diffInDays} days ago`;
    return sessionDate.toLocaleDateString();
  };

  const groupedSessions = filteredSessions.reduce((groups, session) => {
    const date = formatDate(session.createdAt);
    if (!groups[date]) {
      groups[date] = [];
    }
    groups[date].push(session);
    return groups;
  }, {} as Record<string, ChatSession[]>);

  return (
    <>
      {/* Elegant Desktop Toggle Button */}
      <motion.button
        className={cn(
          "hidden md:flex items-center justify-center",
          "absolute top-1/2 -translate-y-1/2 z-50",
          "w-8 h-16 rounded-r-2xl",
          "bg-gradient-to-br from-amber-500 to-red-500",
          "border border-l-0 border-amber-400/30",
          "shadow-2xl hover:shadow-amber-500/25",
          "transition-all duration-500",
          isOpen ? "left-80" : "left-0",
          "group overflow-hidden"
        )}
        onClick={() => setIsOpen(!isOpen)}
        whileHover={{ scale: 1.05, x: 2 }}
        whileTap={{ scale: 0.95 }}
      >
        {/* Shimmer effect */}
        <motion.div
          className="absolute inset-0 bg-gradient-to-r from-transparent via-white/30 to-transparent"
          initial={{ x: '-100%' }}
          animate={{ x: '100%' }}
          transition={{ 
            duration: 2,
            repeat: Infinity,
            repeatDelay: 3,
            ease: "linear"
          }}
        />
        
        {/* Icon container */}
        <motion.div
          className="relative z-10 flex items-center justify-center"
          animate={{ 
            rotate: isOpen ? 0 : 180,
            scale: isOpen ? 1 : 1.1
          }}
          transition={{ duration: 0.4, type: "spring", stiffness: 200 }}
        >
          <ChevronLeft className="w-5 h-5 text-white drop-shadow-lg" />
        </motion.div>
        
        {/* Hover glow effect */}
        <motion.div
          className="absolute inset-0 rounded-r-2xl bg-white/0 group-hover:bg-white/10 transition-all duration-300"
          style={{
            filter: "blur(1px)",
          }}
        />
      </motion.button>

      {/* Sidebar */}
      <AnimatePresence mode="wait">
        <motion.aside
          initial={{ x: -320, opacity: 0 }}
          animate={{ 
            x: isOpen ? 0 : -320,
            opacity: isOpen ? 1 : 0
          }}
          exit={{ x: -320, opacity: 0 }}
          transition={{ type: 'spring', stiffness: 300, damping: 30 }}
          className={cn(
            'relative h-full w-80',
            'bg-gradient-to-b from-slate-900 via-zinc-900 to-stone-900',
            'border-r border-white/10',
            'shadow-2xl',
            'overflow-hidden'
          )}
        >
          {/* Background gradient animation */}
          <motion.div
            className="absolute inset-0 opacity-10"
            animate={{ 
              background: [
                "linear-gradient(135deg, #fbbf24 0%, #dc2626 100%)",
                "linear-gradient(135deg, #dc2626 0%, #fbbf24 100%)",
                "linear-gradient(135deg, #fbbf24 0%, #dc2626 100%)"
              ]
            }}
            transition={{ duration: 10, repeat: Infinity, ease: "linear" }}
          />

          <div className="relative flex h-full flex-col backdrop-blur-sm">
            {/* Header */}
            <div className="border-b border-white/10 bg-black/20 p-6">
              <div className="mb-6 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <motion.div
                    className="p-2 rounded-lg bg-gradient-to-br from-amber-500/20 to-red-500/20"
                    whileHover={{ scale: 1.05 }}
                    whileTap={{ scale: 0.95 }}
                  >
                    <Scale className="h-6 w-6 text-amber-400" />
                  </motion.div>
                  <div>
                    <h1 className="text-xl font-semibold text-white">Legal AI</h1>
                    <p className="text-xs text-white/60">Chat History</p>
                  </div>
                </div>
                <Button
                  variant="ghost"
                  size="icon"
                  className="md:hidden text-white/80 hover:text-white"
                  onClick={() => setIsOpen(false)}
                >
                  <X className="h-5 w-5" />
                </Button>
              </div>
              
              <motion.button
                onClick={onNewChat}
                className="w-full px-4 py-3 rounded-xl bg-gradient-to-r from-amber-500 to-red-500 text-white font-medium shadow-lg hover:shadow-xl transition-all duration-300"
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
              >
                <div className="flex items-center justify-center gap-2">
                  <Plus className="h-5 w-5" />
                  <span>New Chat</span>
                </div>
              </motion.button>
            </div>

            {/* Search */}
            <div className="p-4 border-b border-white/10 bg-black/10">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-white/40" />
                <input
                  type="text"
                  placeholder="Search conversations..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full rounded-lg bg-white/5 border border-white/10 py-2 pl-10 pr-4 text-sm text-white placeholder-white/40 focus:border-amber-500/50 focus:bg-white/10 focus:outline-none transition-all duration-200"
                />
              </div>
            </div>

            {/* Sessions List */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              {isLoading ? (
                <div className="flex items-center justify-center py-8">
                  <div className="h-8 w-8 animate-spin rounded-full border-2 border-amber-500 border-t-transparent" />
                </div>
              ) : Object.keys(groupedSessions).length === 0 ? (
                <div className="text-center py-8">
                  <p className="text-white/40 text-sm">No conversations yet</p>
                  <p className="text-white/30 text-xs mt-1">Start a new chat to begin</p>
                </div>
              ) : (
                <AnimatePresence>
                  {Object.entries(groupedSessions).map(([date, sessions]) => (
                    <motion.div
                      key={date}
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: -10 }}
                      className="space-y-2"
                    >
                      <h3 className="flex items-center gap-2 text-xs font-medium text-white/40 uppercase tracking-wider px-2">
                        <Calendar className="h-3 w-3" />
                        {date}
                      </h3>
                      {sessions.map((session) => (
                        <motion.div
                          key={session.id}
                          className={cn(
                            'group relative w-full rounded-xl p-3 transition-all duration-200 cursor-pointer',
                            'border border-transparent',
                            currentSessionId === session.id
                              ? 'bg-gradient-to-r from-amber-500/20 to-red-500/20 border-amber-500/30'
                              : 'hover:bg-white/5 hover:border-white/10'
                          )}
                          whileHover={{ x: 4 }}
                          whileTap={{ scale: 0.98 }}
                        >
                          <div 
                            className="flex items-start gap-3"
                            onClick={() => onSessionSelect(session.id)}
                          >
                            <div className={cn(
                              "mt-0.5 rounded-lg p-1.5",
                              currentSessionId === session.id
                                ? "bg-amber-500/20"
                                : "bg-white/10 group-hover:bg-white/20"
                            )}>
                              <MessageSquare className="h-4 w-4 text-white/80" />
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="font-medium text-white/90 truncate">
                                {session.title}
                              </p>
                              <div className="mt-1 flex items-center gap-2 text-xs text-white/40">
                                <Clock className="h-3 w-3" />
                                <span>{new Date(session.updatedAt).toLocaleTimeString()}</span>
                                <span>•</span>
                                <span>{session.messages.length} messages</span>
                              </div>
                            </div>
                            <motion.button
                              onClick={(e) => handleDeleteSession(session.id, e)}
                              className="opacity-0 group-hover:opacity-100 transition-opacity duration-200 p-1 rounded hover:bg-white/10"
                              whileHover={{ scale: 1.1 }}
                              whileTap={{ scale: 0.9 }}
                            >
                              <X className="h-4 w-4 text-white/40 hover:text-red-400" />
                            </motion.button>
                          </div>
                          
                          {currentSessionId === session.id && (
                            <motion.div
                              className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-8 bg-gradient-to-b from-amber-400 to-red-400 rounded-r"
                              layoutId="activeSession"
                              transition={{ type: "spring", stiffness: 300, damping: 30 }}
                            />
                          )}
                        </motion.div>
                      ))}
                    </motion.div>
                  ))}
                </AnimatePresence>
              )}
            </div>

            {/* Footer */}
            <div className="border-t border-white/10 bg-black/20 p-4">
              <div className="space-y-2">
                <button className="flex items-center gap-2 w-full px-3 py-2 text-sm text-white/60 hover:text-white hover:bg-white/5 rounded-lg transition-colors duration-200">
                  <Settings className="h-4 w-4" />
                  Settings
                </button>
                <button className="flex items-center gap-2 w-full px-3 py-2 text-sm text-red-400/80 hover:text-red-400 hover:bg-red-500/5 rounded-lg transition-colors duration-200">
                  <LogOut className="h-4 w-4" />
                  Sign Out
                </button>
              </div>
            </div>
          </div>
        </motion.aside>
      </AnimatePresence>

      {/* Mobile overlay */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-40 bg-black/50 backdrop-blur-sm md:hidden"
            onClick={() => setIsOpen(false)}
          />
        )}
      </AnimatePresence>

      {/* Mobile Toggle Button */}
      <Button
        variant="ghost"
        size="icon"
        className="fixed left-4 bottom-4 z-50 md:hidden bg-gradient-to-r from-slate-800 to-zinc-800 border border-white/20 shadow-xl"
        onClick={() => setIsOpen(!isOpen)}
      >
        {isOpen ? <X className="h-5 w-5 text-white" /> : <Menu className="h-5 w-5 text-white" />}
      </Button>
    </>
  );
} 