'use client';

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { AlertCircle, Loader2, Sparkles, Scale } from 'lucide-react';
import { Message } from './Message';
import { ChatInput } from './ChatInput';
import { Card } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Message as MessageType } from '@/lib/types';
import { chatService } from '@/services/chat.service';
import { cn } from '@/lib/utils/cn';

interface ChatContainerProps {
  sessionId?: string;
  className?: string;
}

const SUGGESTIONS = [
  'What are the recent amendments to the Indian Penal Code?',
  'Explain Article 21 of the Constitution',
  'What is the procedure for filing a PIL?',
  'Rights of an arrested person in India',
  'Difference between bail and anticipatory bail',
];

export function ChatContainer({ sessionId: initialSessionId, className }: ChatContainerProps) {
  const [messages, setMessages] = useState<MessageType[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [sessionId, setSessionId] = useState<string | undefined>(initialSessionId);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const scrollAreaRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, scrollToBottom]);

  // Load chat history if sessionId exists
  useEffect(() => {
    if (sessionId) {
      loadChatHistory();
    }
  }, [sessionId]);

  const loadChatHistory = async () => {
    if (!sessionId) return;
    
    try {
      const history = await chatService.getChatHistory(sessionId);
      setMessages(history);
    } catch (err) {
      console.error('Failed to load chat history:', err);
      setError('Failed to load chat history');
    }
  };

  const handleSendMessage = async (content: string) => {
    if (!content.trim() || isLoading) return;

    setError(null);
    const userMessage: MessageType = {
      id: `temp-${Date.now()}`,
      role: 'user',
      content,
      timestamp: new Date(),
    };

    setMessages((prev) => [...prev, userMessage]);
    setIsLoading(true);
    setIsTyping(true);

    // Add a placeholder for the assistant's response
    const assistantPlaceholder: MessageType = {
      id: `temp-assistant-${Date.now()}`,
      role: 'assistant',
      content: '',
      timestamp: new Date(),
    };
    setMessages((prev) => [...prev, assistantPlaceholder]);

    try {
      const response = await chatService.sendMessage(content, sessionId);
      
      // Update the session ID if this is a new conversation
      if (!sessionId && response.sessionId) {
        setSessionId(response.sessionId);
      }

      // Replace the placeholder with the actual response
      setMessages((prev) => 
        prev.map((msg) =>
          msg.id === assistantPlaceholder.id
            ? {
                ...response.message,
                id: response.message.id || assistantPlaceholder.id,
              }
            : msg
        )
      );
    } catch (err) {
      console.error('Failed to send message:', err);
      setError('Failed to send message. Please try again.');
      
      // Remove the typing message on error
      setMessages((prev) => prev.filter((msg) => !msg.id.startsWith('temp-assistant')));
    } finally {
      setIsLoading(false);
      setIsTyping(false);
    }
  };

  const handleNewChat = () => {
    setMessages([]);
    setSessionId(undefined);
    setError(null);
  };

  return (
    <div className={cn('flex h-full flex-col relative', className)}>
      {/* Enhanced gradient background */}
      <div className="absolute inset-0 bg-gradient-to-br from-amber-900/10 via-transparent to-red-900/10" />
      
      {/* Header with glass morphism */}
      <div className="relative backdrop-blur-md bg-black/50 border-b border-white/10">
        <div className="flex items-center justify-between px-6 py-4">
          <div className="flex items-center gap-3">
            <motion.div
              className="p-2 rounded-lg bg-gradient-to-br from-amber-500/20 to-red-500/20"
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
            >
              <Scale className="h-5 w-5 text-amber-400" />
            </motion.div>
            <div>
              <h2 className="text-lg font-semibold text-white">Legal Assistant</h2>
              <p className="text-sm text-gray-400">
                AI-powered Indian law consultation
              </p>
            </div>
          </div>
          <motion.button
            onClick={handleNewChat}
            className="px-4 py-2 rounded-lg bg-gradient-to-r from-amber-500 to-red-500 text-white text-sm font-medium shadow-lg hover:shadow-xl transition-all duration-300"
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            New Chat
          </motion.button>
        </div>
      </div>

      {/* Messages Area */}
      <div
        ref={scrollAreaRef}
        className="flex-1 overflow-y-auto relative"
      >
        {messages.length === 0 ? (
          <div className="flex h-full items-center justify-center p-8">
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5 }}
              className="max-w-2xl w-full"
            >
              <Card variant="glass" className="backdrop-blur-xl bg-black/50 border border-white/10 shadow-2xl">
                <div className="space-y-6 p-8">
                  <motion.div
                    className="mx-auto h-20 w-20 rounded-full bg-gradient-to-br from-amber-500 to-red-500 p-4 shadow-xl"
                    animate={{ 
                      rotate: [0, 10, -10, 0],
                      scale: [1, 1.1, 1],
                    }}
                    transition={{ 
                      duration: 4,
                      repeat: Infinity,
                      ease: "easeInOut"
                    }}
                  >
                    <Scale className="h-full w-full text-white" />
                  </motion.div>
                  <div className="text-center">
                    <h3 className="text-2xl font-bold bg-gradient-to-r from-amber-400 to-red-400 bg-clip-text text-transparent">
                      Welcome to Your Legal Assistant
                    </h3>
                    <p className="mt-3 text-gray-400">
                      I can help you understand Indian law, find relevant cases, and guide you through legal procedures.
                      All information is sourced from official legal databases.
                    </p>
                  </div>
                  <div className="flex flex-wrap justify-center gap-3">
                    {SUGGESTIONS.slice(0, 3).map((suggestion, index) => (
                      <motion.button
                        key={index}
                        onClick={() => handleSendMessage(suggestion)}
                        className="px-4 py-2 rounded-lg bg-black/50 border border-amber-800 text-sm text-amber-200 hover:border-amber-600 hover:bg-amber-900/20 transition-all duration-200"
                        whileHover={{ scale: 1.05, y: -2 }}
                        whileTap={{ scale: 0.95 }}
                      >
                        <Sparkles className="inline-block w-4 h-4 mr-2 text-amber-500" />
                        {suggestion}
                      </motion.button>
                    ))}
                  </div>
                </div>
              </Card>
            </motion.div>
          </div>
        ) : (
          <div className="pb-4">
            <AnimatePresence>
              {messages.map((message, index) => (
                <Message
                  key={message.id}
                  message={message}
                  isTyping={isTyping && index === messages.length - 1 && message.role === 'assistant' && !message.content}
                />
              ))}
            </AnimatePresence>
            <div ref={messagesEndRef} />
          </div>
        )}
      </div>

      {/* Error Display */}
      <AnimatePresence>
        {error && (
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 10 }}
            className="mx-4 mb-2"
          >
            <Card variant="bordered" className="border-red-900 bg-red-950/50 backdrop-blur-sm">
              <div className="flex items-center gap-2 text-sm text-red-300 p-4">
                <AlertCircle className="h-4 w-4" />
                <span>{error}</span>
              </div>
            </Card>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Input Area */}
      <div className="p-4">
        <ChatInput
          onSendMessage={handleSendMessage}
          isLoading={isLoading}
          suggestions={SUGGESTIONS}
        />
      </div>
    </div>
  );
} 